export default async function setProductAvailability(
  productId,
  startDate,
  endDate
) {
  const location = window.location.origin;
  const endpoint = "/wp-json/inpost/v1/izi/hot-product/set-availability";

  const response = await fetch(`${location}${endpoint}`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-WP-Nonce": window.inpostPayApi?.nonce,
      cache: "no-cache",
    },
    body: JSON.stringify([
      {
        product_id: productId,
        start_date: startDate,
        end_date: endDate,
      },
    ]),
  });

  const data = await response.json();
  if (!response.ok) throw new Error(data.error);
  if (response.status !== 200) return;
  return data;
}
