import showSuccessAlert from "./showSuccessAlert";
import setProductAvailability from "../api/setProductAvailability";
import formatDateToISOString from "../helpers/formatDateToISOString";
import formatISOStringToDate from "../helpers/formatISOStringToDate";
import showAlert from "./showAlert";

export default function loadPeriodPicker({ element, afterAvailabilityUpdate }) {
  const lang = document.querySelector(".hot-products-wrapper").dataset.lang;
  const availabilitySetText = document.querySelector(".hot-products-wrapper")
    ?.dataset?.availabilitySetText;

  jQuery(element).flatpickr({
    mode: "range",
    enableTime: true,
    locale: lang,
    time_24hr: true,
    onChange: function (selectedDates, dateStr, instance) {
      if (selectedDates.length === 2) {
        const startDate = selectedDates[0];
        const endDate = selectedDates[1];

        if (
          startDate.getFullYear() === endDate.getFullYear() &&
          startDate.getMonth() === endDate.getMonth() &&
          startDate.getDate() === endDate.getDate()
        ) {
          if (
            endDate.getHours() <= startDate.getHours() &&
            endDate.getMinutes() <= startDate.getMinutes()
          ) {
            const newEndDate = new Date(startDate.getTime());
            newEndDate.setHours(startDate.getHours() + 1);

            instance.setDate([startDate, newEndDate], false);
          }
        }
      }

      if (selectedDates.length === 1) {
        instance.set("minTime", "00:00");
      }
    },
    onReady: function (selectedDates, dateStr, instance) {
      const startDate = formatISOStringToDate(
        instance.element.parentElement.dataset.startDate
      );
      const endDate = formatISOStringToDate(
        instance.element.parentElement.dataset.endDate
      );

      if (startDate && endDate) {
        instance.setDate([startDate, endDate], false);
      }
    },
    onClose: function (selectedDates, dateStr, instance) {
      if (selectedDates.length === 2) {
        const row = instance.element.closest("tr");
        const productId = row.dataset.productId;
        const startDate = formatDateToISOString(selectedDates[0]);
        const endDate = formatDateToISOString(selectedDates[1]);

        if (startDate && endDate) {
          const loadingEl = document.createElement("div");
          loadingEl.className = "datepicker-loading";
          loadingEl.style.width = "30px";
          loadingEl.style.height = "30px";
          loadingEl.innerHTML = `
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" style="height: 100%;">
              <radialGradient id="loader-gradient-hot-products" cx=".66" fx=".66" cy=".3125" fy=".3125" gradientTransform="scale(1.5)">
                <stop offset="0" stop-color="#0085BA"/>
                <stop offset=".3" stop-color="#0085BA" stop-opacity=".9"/>
                <stop offset=".6" stop-color="#0085BA" stop-opacity=".6"/>
                <stop offset=".8" stop-color="#0085BA" stop-opacity=".3"/>
                <stop offset="1" stop-color="#0085BA" stop-opacity="0"/>
              </radialGradient>
              <circle transform-origin="center" fill="none" stroke="url(#loader-gradient-hot-products)" stroke-width="15" stroke-linecap="round" stroke-dasharray="200 1000" stroke-dashoffset="0" cx="100" cy="100" r="70">
                <animateTransform type="rotate" attributeName="transform" calcMode="spline" dur="2" values="360;0" keyTimes="0;1" keySplines="0 0 1 1" repeatCount="indefinite"/>
              </circle>
              <circle transform-origin="center" fill="none" opacity=".2" stroke="#0085BA" stroke-width="15" stroke-linecap="round" cx="100" cy="100" r="70"/>
            </svg>
          `;
          instance.element.parentElement.appendChild(loadingEl);
          const dataApiErrorTitle =
            instance.element.parentElement.dataset.apiErrorTitle;

          setProductAvailability(productId, startDate, endDate)
            .then((response) => {
              if (response) {
                if (response?.updated?.length === 0) {
                  showAlert(dataApiErrorTitle);
                  return;
                }

                row.dataset.productAvailability = `${startDate} - ${endDate}`;
                instance.element.parentElement.dataset.startDate = startDate;
                instance.element.parentElement.dataset.endDate = endDate;
                showSuccessAlert(availabilitySetText);

                const status = response?.updated[0]?.status;

                if (status !== "null" && status !== null) {
                  const statusElement = row.querySelector(
                    ".hot-products__status"
                  );

                  if (!statusElement) return;

                  const hotProductsWrapper = document.querySelector(
                    ".hot-products-wrapper"
                  );

                  statusElement.classList.remove(
                    "hot-products__status--rejected"
                  );
                  statusElement.classList.remove(
                    "hot-products__status--accepted"
                  );

                  if (status === "INACTIVE") {
                    statusElement.classList.add(
                      "hot-products__status--rejected"
                    );
                    statusElement.textContent =
                      hotProductsWrapper?.dataset?.rejectedText;
                  } else {
                    statusElement.classList.add(
                      "hot-products__status--accepted"
                    );
                    statusElement.innerHTML =
                      `<img src="${
                        document.querySelector(".hot-products-wrapper").dataset.pluginUrl
                      }../../../assets/img/hp-accepted.svg" alt="">
                     <span>${document.querySelector(".hot-products-wrapper")?.dataset?.acceptedText}</span>`;
                  }
                }
              }
            })
            .catch((error) => {
              showAlert(dataApiErrorTitle);
              console.error("Error setting product availability:", error);
              instance.clear();
            })
            .finally(() => {
              const loadingElement =
                instance.element.parentElement.querySelector(
                  ".datepicker-loading"
                );
              if (loadingElement) {
                loadingElement.remove();
              }

              if (afterAvailabilityUpdate) {
                afterAvailabilityUpdate();
              }
            });
        }
      } else {
        const startDate = instance.element.parentElement.dataset.startDate;
        const endDate = instance.element.parentElement.dataset.endDate;

        if (startDate !== "null" && endDate !== "null") {
          const startDateFormatted = formatISOStringToDate(startDate);
          const endDateFormatted = formatISOStringToDate(endDate);

          instance.setDate([startDateFormatted, endDateFormatted], false);
          return;
        }

        setTimeout(() => {
          instance.clear();
        }, 10);
      }
    },
  });
}
