import updateProductsList from "./updateProductList";

export default function loadSearchs() {
  const categoriesSearch = document.querySelector(
    ".hot-products__search--categories"
  );
  const productsSearch = document.querySelector(
    ".hot-products__search--products"
  );

  if (!categoriesSearch || !productsSearch) {
    return;
  }

  categoriesSearch.addEventListener("input", (e) => {
    const searchValue = e.target.value.toLowerCase();
    const categoryRows = document.querySelectorAll(
      ".hot-products__table--categories tbody tr"
    );

    let visibleCount = 0;
    categoryRows.forEach((row) => {
      const categoryName =
        row
          .querySelector(".hot-products__td--product-name")
          ?.textContent?.toLowerCase() || "";
      const categoryId =
        row
          .querySelector(".hot-products__td--id")
          ?.textContent?.toLowerCase() || "";

      const isVisible =
        categoryName.includes(searchValue) || categoryId.includes(searchValue);

      row.style.display = isVisible ? "" : "none";
      if (isVisible) visibleCount++;
    });

    const noResultsText = document.querySelector(".hot-products-wrapper")
      ?.dataset?.noResultsMessage;

    const noResultsMessage = document.querySelector(
      ".hot-products__no-results"
    );
    if (!noResultsMessage) {
      const tbody = document.querySelector(
        ".hot-products__table--categories tbody"
      );
      const messageRow = document.createElement("tr");
      messageRow.className = "hot-products__no-results";
      messageRow.innerHTML = `<td colspan="3" style="text-align: center;">${noResultsText}</td>`;
      tbody.appendChild(messageRow);
    }

    const existingMessage = document.querySelector(".hot-products__no-results");
    existingMessage.style.display = visibleCount === 0 ? "" : "none";
  });

  let timeout = null;
  productsSearch.addEventListener("input", (e) => {
    if (timeout) clearTimeout(timeout);

    timeout = setTimeout(async () => {
      updateProductsList();
    }, 300);
  });
}
