import updateProductsList from "./updateProductList";

export default function addCategoriesLinks() {
  const categoriesTable = document.querySelector(
    ".hot-products__table-wrapper--categories"
  );
  const productsTable = document.querySelector(
    ".hot-products__table-wrapper--products"
  );

  if (!categoriesTable || !productsTable) {
    return;
  }

  const productsTableBody = productsTable.querySelector("tbody");

  const loaderHTML = `
    <tr>
      <td colspan="4" style="text-align: center">
        <div class="hot-products__loader">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" style="height: 40px;">
            <radialGradient id="loader-gradient-products" cx=".66" fx=".66" cy=".3125" fy=".3125" gradientTransform="scale(1.5)">
              <stop offset="0" stop-color="#0085BA"/>
              <stop offset=".3" stop-color="#0085BA" stop-opacity=".9"/>
              <stop offset=".6" stop-color="#0085BA" stop-opacity=".6"/>
              <stop offset=".8" stop-color="#0085BA" stop-opacity=".3"/>
              <stop offset="1" stop-color="#0085BA" stop-opacity="0"/>
            </radialGradient>
            <circle transform-origin="center" fill="none" stroke="url(#loader-gradient-products)" stroke-width="15" stroke-linecap="round" stroke-dasharray="200 1000" stroke-dashoffset="0" cx="100" cy="100" r="70">
              <animateTransform type="rotate" attributeName="transform" calcMode="spline" dur="2" values="360;0" keyTimes="0;1" keySplines="0 0 1 1" repeatCount="indefinite"/>
            </circle>
            <circle transform-origin="center" fill="none" opacity=".2" stroke="#0085BA" stroke-width="15" stroke-linecap="round" cx="100" cy="100" r="70"/>
          </svg>
        </div>
      </td>
    </tr>
  `;

  categoriesTable.addEventListener("click", async (e) => {
    const productLink = e.target.closest(".hot-products__product-link");
    if (!productLink) return;

    categoriesTable.classList.add("hot-products__table-wrapper--hidden");
    productsTable.classList.remove("hot-products__table-wrapper--hidden");

    const categoryName = productLink.dataset.categoryName;
    productsTable.dataset.categoryName = categoryName;

    const categoryId = productLink.dataset.categoryId;
    productsTable.dataset.categoryId = categoryId;
    productsTableBody.innerHTML = loaderHTML;

    updateProductsList();
  });
}
