import getHotProducts from "../api/getHotProducts";
import deleteHotProduct from "../api/deleteHotProduct";
import deleteAllHotProducts from "../api/deleteAllHotProducts";
import toggleRemoveAllButton from "./toggleRemoveAllButton";
import showAlert from "./showAlert";
import loadPeriodPicker from "./loadPeriodPicker";

export default async function loadHotProducts() {
  const tableBody = document.querySelector(
    ".hot-products__table--hot-products tbody"
  );
  const removeAllButton = document.querySelector(".hot-product__remove-all");

  if (!tableBody || !removeAllButton) return;

  removeAllButton.replaceWith(removeAllButton.cloneNode(true));
  const newRemoveAllButton = document.querySelector(".hot-product__remove-all");

  const loaderHTML = `
    <tr>
      <td colspan="5" style="text-align: center">
        <div class="hot-products__loader">
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 200 200" style="height: 40px;">
            <radialGradient id="loader-gradient-hot-products" cx=".66" fx=".66" cy=".3125" fy=".3125" gradientTransform="scale(1.5)">
              <stop offset="0" stop-color="#0085BA"/>
              <stop offset=".3" stop-color="#0085BA" stop-opacity=".9"/>
              <stop offset=".6" stop-color="#0085BA" stop-opacity=".6"/>
              <stop offset=".8" stop-color="#0085BA" stop-opacity=".3"/>
              <stop offset="1" stop-color="#0085BA" stop-opacity="0"/>
            </radialGradient>
            <circle transform-origin="center" fill="none" stroke="url(#loader-gradient-hot-products)" stroke-width="15" stroke-linecap="round" stroke-dasharray="200 1000" stroke-dashoffset="0" cx="100" cy="100" r="70">
              <animateTransform type="rotate" attributeName="transform" calcMode="spline" dur="2" values="360;0" keyTimes="0;1" keySplines="0 0 1 1" repeatCount="indefinite"/>
            </circle>
            <circle transform-origin="center" fill="none" opacity=".2" stroke="#0085BA" stroke-width="15" stroke-linecap="round" cx="100" cy="100" r="70"/>
          </svg>
        </div>
      </td>
    </tr>
  `;

  tableBody.innerHTML = loaderHTML;

  try {
    const products = await getHotProducts();

    toggleRemoveAllButton(products?.length > 0);

    const acceptedText = document.querySelector(".hot-products-wrapper")
      ?.dataset?.acceptedText;
    const rejectedText = document.querySelector(".hot-products-wrapper")
      ?.dataset?.rejectedText;
    const removeText = document.querySelector(".hot-products-wrapper")?.dataset
      ?.removeText;
    const highlightPeriodText = document.querySelector(".hot-products-wrapper")
      ?.dataset?.highlightPeriodNotSelected;
    const pluginUrl = document.querySelector(".hot-products-wrapper").dataset
      .pluginUrl;

    tableBody.innerHTML = products?.length
      ? products
          .map(
            (product, index) => `
        <tr data-product-id="${product.id}" data-product-availability="${
              product.start_date
            } - ${product.end_date}">
          <td class="hot-products__td hot-products__td--count">${
            index + 1
          }.</td>
          <td class="hot-products__td hot-products__td--product-name">
            <a href="/wp-admin/post.php?post=${
              product.id
            }&action=edit" target="_blank">
              ${product.name}
            </a>
          </td>
          <td class="hot-products__td hot-products__td--id">${product.id}</td>
          <td class="hot-products__td hot-products__td--highlight-period">
            <div class="hot-products__period" data-start-date="${
              product.start_date
            }" data-end-date="${product.end_date}">
                <img src="${pluginUrl}../../../assets/img/period.svg" alt="">
                <input class="hot-products__period-input" type="text" placeholder="${highlightPeriodText}" readonly="readonly">
            </div>
          </td>
          <td class="hot-products__td hot-products__td--actions">
            <div>
              <div class="hot-products__status ${
                product.published
                  ? "hot-products__status--accepted"
                  : "hot-products__status--rejected"
              }">
                ${
                  product.published
                    ? `<img src="${
                        document.querySelector(".hot-products-wrapper").dataset
                          .pluginUrl
                      }../../../assets/img/hp-accepted.svg" alt="">
                     <span>${acceptedText}</span>`
                    : `<span>${rejectedText}</span>`
                }
              </div>
              <button class="inpost-btn inpost-btn--remove-mini">
                <img src="${
                  document.querySelector(".hot-products-wrapper").dataset
                    .pluginUrl
                }../../../assets/img/hp-remove.svg" alt="">
                <span>${removeText}</span>
              </button>
            </div>
          </td>
        </tr>
      `
          )
          .join("")
      : `
        <tr>
          <td colspan="5" style="text-align: center;">
            ${
              document.querySelector(".hot-products-wrapper").dataset
                .noResultsMessage
            }
          </td>
        </tr>
      `;

    const buttons = tableBody.querySelectorAll(".inpost-btn--remove-mini");
    buttons.forEach((button) => {
      const newButton = button.cloneNode(true);
      button.parentNode.replaceChild(newButton, button);
    });

    tableBody.querySelectorAll(".inpost-btn--remove-mini").forEach((button) => {
      button.addEventListener("click", async (e) => {
        const row = e.target.closest("tr");
        const productId = row.dataset.productId;
        const originalContent = row.innerHTML;

        try {
          row.classList.add("removing");
          await deleteHotProduct(productId);

          setTimeout(() => {
            row.remove();

            const remainingRows = tableBody.querySelectorAll("tr");
            remainingRows.forEach((tr, index) => {
              const countWrapper = tr.querySelector(".hot-products__td--count");
              if (countWrapper) {
                countWrapper.innerHTML = `
                  <div class="hot-products__td--count-wrapper">
                    <span>${index + 1}.</span>
                  </div>
                `;
              }
            });

            const totalItemsEl = document.querySelector(
              ".hot-products__pagination-total-items"
            );
            if (totalItemsEl) {
              const currentTotal = parseInt(totalItemsEl.textContent) - 1;
              totalItemsEl.textContent = currentTotal;
            }

            if (!remainingRows.length) {
              tableBody.innerHTML = `
                <tr>
                  <td colspan="5" style="text-align: center;">
                    ${
                      document.querySelector(".hot-products-wrapper").dataset
                        .noResultsMessage
                    }
                  </td>
                </tr>
              `;

              const removeAllButton = document.querySelector(
                ".hot-product__remove-all"
              );
              if (removeAllButton) {
                removeAllButton.style.display = "none";
              }

              if (totalItemsEl) {
                totalItemsEl.textContent = "0";
              }
            }
          }, 300);
        } catch (error) {
          console.error("Error removing product:", error);
          showAlert(error);
          row.classList.remove("removing");
          row.innerHTML = originalContent;
        }
      });
    });

    newRemoveAllButton.addEventListener("click", async () => {
      try {
        const rows = tableBody.querySelectorAll("tr");

        rows.forEach((row) => row.classList.add("removing"));

        await deleteAllHotProducts();

        setTimeout(() => {
          tableBody.innerHTML = `
            <tr>
              <td colspan="5" style="text-align: center;">
                ${
                  document.querySelector(".hot-products-wrapper").dataset
                    .noResultsMessage
                }
              </td>
            </tr>
          `;
          newRemoveAllButton.style.display = "none";
        }, 300);
      } catch (error) {
        showAlert(error);
        console.error("Error removing all products:", error);
        rows.forEach((row) => row.classList.remove("removing"));
      }
    });
  } catch (error) {
    console.error("Error loading hot products:", error);
    showAlert(error);
    toggleRemoveAllButton(false);
    tableBody.innerHTML = `
      <tr>
        <td colspan="5" style="text-align: center; color: var(--hotproducts-red);">
          ${
            document.querySelector(".hot-products-wrapper").dataset
              .apiErrorMessage
          }
        </td>
      </tr>
    `;
  }

  loadPeriodPicker({
    element: ".hot-products__period-input",
  });
}
