import clearSearchs from "./clearSearchs";
import resetSelectedProducts from "./resetSelectedProducts";

export default function productsBackButton() {
  const backButton = document.querySelector(
    ".hot-products__table-actions-products-back-btn"
  );
  const confirmation = document.querySelector(".hot-products-confirmation");

  if (!backButton || !confirmation) return;

  backButton.addEventListener("click", () => {
    const hasSelectedProducts =
      document.querySelectorAll(
        ".hot-products__table--products input[type='checkbox']:checked"
      ).length > 0;

    if (hasSelectedProducts) {
      confirmation.classList.add("hot-products-confirmation--active");
    } else {
      const categoriesWrapper = document.querySelector(
        ".hot-products__table-wrapper--categories"
      );
      const productsWrapper = document.querySelector(
        ".hot-products__table-wrapper--products"
      );
      const popupSelectedInfo = document.querySelector(
        ".hot-products__popup-selected-info--products"
      );

      popupSelectedInfo.classList.remove(
        "hot-products__popup-selected-info--visible"
      );
      categoriesWrapper.classList.remove("hot-products__table-wrapper--hidden");
      productsWrapper.classList.add("hot-products__table-wrapper--hidden");
      clearSearchs();
      resetSelectedProducts();
    }
  });
}
