export default function showAlert(text) {
  const hotProductsWrapper = document.querySelector(".hot-products-wrapper");

  if (!hotProductsWrapper) return;

  const existingAlerts = document.querySelectorAll(".hot-products-error-alert");

  if (existingAlerts.length > 0) {
    existingAlerts.forEach((alert) => {
      alert.remove();
    });
  }

  const template = `    
        <div class="hot-products-error-alert__content">
            <h3 class="hot-products-error-alert__title">${hotProductsWrapper.dataset.apiErrorTitle}</h3>
            <p class="hot-products-error-alert__text">${text}</p>
        </div>`;

  const alert = document.createElement("div");
  alert.classList = "hot-products-error-alert hot-products-error-alert--active";
  alert.innerHTML = template;

  hotProductsWrapper.appendChild(alert);

  setTimeout(() => {
    alert.classList.remove("hot-products-error-alert--active");
  }, 5000);
}
