import showModal from "./hotproducts/modal/showModal";
import hideModals from "./hotproducts/modal/hideModals";
import loadCategories from "./hotproducts/modal/loadCategories";
import loadSearchs from "./hotproducts/modal/loadSearchs";
import productsBackButton from "./hotproducts/modal/productsBackButton";
import clearSearchs from "./hotproducts/modal/clearSearchs";
import resetCategoriesSearch from "./hotproducts/modal/resetCategoriesSearch";
import loadHotProducts from "./hotproducts/modal/loadHotProducts";
import handleProductSelection from "./hotproducts/modal/handleProductSelection";
import resetSelectedProducts from "./hotproducts/modal/resetSelectedProducts";
import handleConfirmationModal from "./hotproducts/modal/handleConfirmationModal";
import handleAddedProductsSave from "./hotproducts/modal/handleAddedProductsSave";

window.addEventListener("load", function () {
  const productsWrapper = document.querySelector(".hot-products-wrapper");

  if (!productsWrapper) {
    return;
  }

  loadHotProducts();

  loadCategories();

  const popupTable = productsWrapper?.querySelector(
    ".hot-products-popup-table"
  );
  const overlay = productsWrapper?.querySelector(".overlay");
  const selectProductsButton = productsWrapper?.querySelector(
    ".hot-products-select-products"
  );
  const closePopupButton = popupTable?.querySelector(
    ".hot-products__popup-close"
  );
  const cancelButton = productsWrapper?.querySelector(
    ".hot-products__table-actions-categories-btn"
  );

  const closeElements = [closePopupButton, cancelButton, overlay];

  closeElements.forEach((element) => {
    element.addEventListener("click", () => {
      hideModals();
      resetCategoriesSearch();
      clearSearchs();
    });
  });

  selectProductsButton.addEventListener("click", () => {
    showModal(popupTable, overlay);
    resetCategoriesSearch();
    clearSearchs();
    resetSelectedProducts();
  });

  loadSearchs();
  productsBackButton();
  handleProductSelection();
  handleAddedProductsSave();
  handleConfirmationModal();
});
